import { Transform, Type } from 'class-transformer';
import {
  IsArray,
  IsBoolean,
  IsDateString,
  IsEnum,
  IsInt,
  IsNumber,
  IsOptional,
  IsString,
  Min,
  ValidateIf,
  ValidateNested,
} from 'class-validator';
import { JSONSchema } from 'class-validator-jsonschema';

import { HttpPaginatedResponse } from '@Libs/types/HttpPaginatedResponse';

import { UnitTime } from '@Enums/Day';
import { CustomerType } from '@Enums/hotels/Customer';
import {
  CalculationServiceType,
  CancellationType,
  FeeCalculationType,
  MealPlan,
  SurchargeFeeType,
  UnitType,
} from '@Enums/hotels/Hotel';
import { PromotionType } from '@Enums/hotels/HotelPromotion';
import { BedType } from '@Enums/hotels/HotelRoom';

import { AmenityDto } from '@Rests/types/hotel/AmenityDto';
import { DestinationDto } from '@Rests/types/hotel/DestinationDto';
import { FileDto } from '@Rests/types/hotel/FileDto';
import { HotelDto } from '@Rests/types/hotel/HotelDto';
import { CancellationPolicy } from '@Rests/types/hotel/PromotionType';

//#region Search Request Types

class HotelSearchChildDto {
  @IsInt()
  age: number;
}

class HotelSearchRoomDto {
  @IsInt()
  @Min(1)
  adults: number;

  @IsOptional()
  @IsArray()
  @ValidateNested({ each: true })
  @Type(() => HotelSearchChildDto)
  children?: HotelSearchChildDto[];
}

export class HotelPriceSearchParams {
  @IsOptional()
  @Type(() => Number)
  @IsInt()
  destinationId?: number;

  @IsOptional()
  @Type(() => Number)
  @IsInt()
  hotelId?: number;

  @IsOptional()
  @IsString()
  searchId?: string;

  @ValidateIf(o => !o.searchId)
  @JSONSchema({ format: 'date' })
  @IsDateString()
  checkInDate: Date;

  @ValidateIf(o => !o.searchId)
  @JSONSchema({ format: 'date' })
  @IsDateString()
  checkOutDate: Date;

  @IsOptional()
  @IsArray()
  @ValidateNested({ each: true })
  @Type(() => HotelSearchRoomDto)
  rooms?: HotelSearchRoomDto[];

  @IsOptional()
  @Type(() => Number)
  @IsInt()
  @Min(1)
  page?: number = 1;

  @IsOptional()
  @Type(() => Number)
  @IsInt()
  @Min(1)
  size?: number = 10;
}
//#endregion
export class HotelSearchSuggestionQuery {
  @IsString()
  q: string;

  @IsOptional()
  @Type(() => Number)
  @IsInt()
  @Min(1)
  limit?: number = 10;
}

//#region Search Response Types

class SearchRoomRes {
  @IsInt()
  id: number;

  @IsString()
  code: string;

  @IsString()
  localName: string;

  @IsString()
  globalName: string;

  @IsNumber()
  maxCapacity: number;

  @IsNumber()
  maxAdults: number;

  @IsNumber()
  maxChildren: number;

  @IsOptional()
  @IsNumber()
  area?: number;

  @IsOptional()
  @IsEnum(BedType, { each: true })
  bedTypes?: BedType[];

  @IsBoolean()
  isBreakfastIncluded: boolean;

  @IsOptional()
  @IsArray()
  amenities?: Partial<AmenityDto>[];

  @IsOptional()
  @IsArray()
  files?: FileDto[];
}

export class AppliedSurchargeRes {
  @IsNumber()
  id: number;

  @JSONSchema({ format: 'date' })
  @IsDateString()
  stayDate: Date;

  @IsEnum(MealPlan)
  mealPlan: MealPlan;

  @IsEnum(SurchargeFeeType)
  type: SurchargeFeeType;

  @IsEnum(CustomerType)
  customerType: CustomerType;

  @IsOptional()
  @IsInt()
  age?: number;

  @IsEnum(UnitType)
  unitType: UnitType;

  @IsNumber()
  unitAmount: number;

  /** Số lượng áp dụng phụ phí */
  @IsInt()
  quantity: number;

  /** Tổng phụ phí */
  @IsNumber()
  total: number;

  /** Số đêm lưu trú */
  @IsNumber()
  @IsOptional()
  night: number;
}

export class AppliedPromotionRes {
  @IsInt()
  promotionId: number;

  @IsString()
  promotionName: string;

  @IsEnum(PromotionType)
  promotionType: PromotionType;

  @IsNumber()
  promotionRate: number;

  @IsOptional()
  @IsString()
  displayText?: string;

  @IsOptional()
  @IsString({ each: true })
  valueAddTypes?: string[];

  //#region Điều kiện hoàn hủy
  @IsOptional()
  @IsBoolean()

import { Body, Get, JsonController, OnNull, OnUndefined, Param, Post, QueryParams } from 'routing-controllers';
import { OpenAPI, ResponseSchema } from 'routing-controllers-openapi';
import { Service } from 'typedi';
import winston from 'winston';

import { Logger } from '@Decorators/Logger';
import { RegContext } from '@Decorators/RegistryContext';

import { HotelStatus } from '@Enums/hotels/Hotel';

import { ServiceRegistryGuard } from '@Middlewares/guard/ServiceRegistryGuard';

import { ServiceRegistry } from '@Entities/ServiceRegistry';

import { HotelService } from '@Services/HotelService';
import { RequestQuoteService } from '@Services/RequestQuoteService';

import { BaseQueryParams } from '@Rests/types/common/BaseQueryParams';
import { AmenitiesResponse, AmenityQueryParams } from '@Rests/types/hotel/AmenityDto';
import { BookingQueryParams, CreateBookingDto, VerifyBookingPricesDto } from '@Rests/types/hotel/BookingDto';
import { GeoCityDto, GeoCountryDto, GeoDistrictDto, GeoWardDto } from '@Rests/types/hotel/GeoDto';
import { HotelDto } from '@Rests/types/hotel/HotelDto';
import { GetHotelParams, HotelQueryParams } from '@Rests/types/hotel/HotelQueryParams';
import {
  HotelPriceSearchParams,
  HotelPriceSearchResponse,
  HotelSearchSuggestionQuery,
  HotelSearchSuggestionResponse,
} from '@Rests/types/hotel/HotelSearchDto';
import { RoomDto, RoomsResponse } from '@Rests/types/hotel/RoomDto';
import { SearchHotelQueryParams, SearchHotelResponses } from '@Rests/types/hotel/SearchHotelParams';
import { SuggestHotelQueryDto, SuggestHotelResponseDto } from '@Rests/types/hotel/SuggestHotelDto';
import { ConfirmPaymentDto, CreateRequestQuoteExDto, RequestQuoteExParamsDto } from '@Rests/types/RequestQuoteDto';

@Service()
@JsonController('/external/hotels')
@ServiceRegistryGuard()
export class HotelExternalController {
  constructor(
    @Logger(module) private readonly logger: winston.Logger,
    private readonly hotelService: HotelService,
    private readonly requestQuoteService: RequestQuoteService,
  ) {}

  // #region HOTEL SEARCH
  @Get('/completions')
  @OpenAPI({ summary: 'Suggest destinations or hotels for autocomplete', tags: ['Hotel Search'] })
  @ResponseSchema(HotelSearchSuggestionResponse)
  async completions(@QueryParams() query: HotelSearchSuggestionQuery) {
    this.logger.info('HotelSearchController::suggest', query);
    return this.hotelService.completions(query);
  }

  @Post('/search-prices')
  @OpenAPI({ summary: 'Search hotel prices by destination and stay dates', tags: ['Hotel Search'] })
  @ResponseSchema(HotelPriceSearchResponse)
  async searchPrices(@Body() body: HotelPriceSearchParams) {
