import { routingControllersToSpec } from 'routing-controllers-openapi';
import * as swaggerUi from 'swagger-ui-express';
import { Express } from 'express';

import { env } from '@Libs/env';

const OPENAPI_COMPONENT_REF = /^#\/components\/([^/]+)\/([^/]+)$/;

const collectRefs = (node: any, refs: Set<string>) => {
  if (!node) {
    return;
  }

  if (Array.isArray(node)) {
    node.forEach(item => collectRefs(item, refs));
    return;
  }

  if (typeof node !== 'object') {
    return;
  }

  Object.entries(node).forEach(([key, value]) => {
    if (key === '$ref' && typeof value === 'string' && value.startsWith('#/components/')) {
      refs.add(value);
      return;
    }

    collectRefs(value, refs);
  });
};

const buildFilteredComponents = (sourceComponents: Record<string, any>, sourcePaths: Record<string, any>) => {
  const pendingRefs = new Set<string>();
  const visitedRefs = new Set<string>();
  const collectedByType: Record<string, Set<string>> = {};

  collectRefs(sourcePaths, pendingRefs);

  while (pendingRefs.size > 0) {
    const nextRef = pendingRefs.values().next().value as string;
    pendingRefs.delete(nextRef);

    if (visitedRefs.has(nextRef)) {
      continue;
    }

    visitedRefs.add(nextRef);
    const matched = nextRef.match(OPENAPI_COMPONENT_REF);

    if (!matched) {
      continue;
    }

    const [, componentType, componentName] = matched;
    const componentBucket = sourceComponents?.[componentType];
    const componentNode = componentBucket?.[componentName];

    if (!componentNode) {
      continue;
    }

    if (!collectedByType[componentType]) {
      collectedByType[componentType] = new Set<string>();
    }

    collectedByType[componentType].add(componentName);

    const nestedRefs = new Set<string>();
    collectRefs(componentNode, nestedRefs);
    nestedRefs.forEach(ref => {
      if (!visitedRefs.has(ref)) {
        pendingRefs.add(ref);
      }
    });
  }

  return Object.entries(collectedByType).reduce((acc, [componentType, componentNames]) => {
    acc[componentType] = [...componentNames].reduce((bucket, name) => {
      bucket[name] = sourceComponents[componentType][name];
      return bucket;
    }, {} as Record<string, any>);

    return acc;
  }, {} as Record<string, any>);
};

export const swaggerSetup = (app: Express) => {
  if (env.swagger.enabled) {
    const schemas = validationMetadatasToSchemas({
      refPointerPrefix: '#/components/schemas/',
      classTransformerMetadataStorage,
    });

    const baseUrl = `${env.app.schema}://${env.app.host}:${env.app.externalPort}`;
    const spec = routingControllersToSpec(
      getMetadataArgsStorage(),
      {},
      {
        components: {
          schemas,
          securitySchemes: {
            BearerToken: {
              type: 'http',
              name: 'Bearer Token',
              scheme: 'bearer',
              description: 'Pass the jwt accessToken',
              bearerFormat: 'JWT',
            },
            DynamicAPIKey: {
              type: 'apiKey',
              in: 'header',
              name: 'x-api-key',
              required: true,
              description: 'Use the key and API key issued when you registered with us (key default: x-api-key)',
            },
            RegistryAPIKey: {
              type: 'apiKey',
              in: 'header',
              name: 'reg-api-key',
              required: true,
              description: 'Service API key provided upon account creation',
            },
          },
        },
        info: {
          title: `${env.app.name} Swagger API Documentation`,
          description: `${baseUrl}${env.swagger.route}`,
          version: '1.0.0',
        },
      },
    );

    // Add npm infos to the swagger doc

    spec.servers = [
      { url: `${baseUrl}${env.app.externalRoutePrefix}` },
      { url: `http://localhost:${env.app.port}${env.app.routePrefix}` },
    ];

    // ── Internal Swagger (/swagger): all endpoints ──
    if (env.swagger.internalEnabled) {
      app.use(env.swagger.route, swaggerUi.serveFiles(spec), swaggerUi.setup());

      app.use(env.swagger.apiDocs, (req: any, res: any) => {
        const { host } = req.headers;
        res.status(200).send({ ...spec, host });
      });
    }

    // ── External Swagger (/swagger/hotel): only /external/hotels/* endpoints ──
    const externalHotelPaths = Object.keys(spec.paths).reduce((acc, path) => {
      if (path.startsWith('/external/hotels/')) {
        acc[path] = spec.paths[path];
      }

      return acc;
    }, {} as Record<string, any>);

    const filteredExternalComponents = buildFilteredComponents(spec.components || {}, externalHotelPaths);

    const externalSpec = {
      openapi: '3.0.0',
      info: {
        title: `Airdata Hotel Service Agent API Swagger API Documentation`,
        version: '1.0.0',
        description: `
[**⬇️ Download OpenAPI JSON Schema**](..${env.swagger.externalHotelApiDocs})

### Authentication Guide
All external APIs require authentication using an **API Key**.

**How to use:**
1. Obtain the \`reg-api-key\` provided for your account.
2. Include the \`reg-api-key\` in the **Headers** of every HTTP Request.

**cURL Example:**
\`\`\`bash
curl -X GET "${baseUrl}${env.app.externalRoutePrefix}/external/hotels/completions?q=hà%20nội" \
-H "reg-api-key: YOUR_API_KEY_HERE"
\`\`\`

**Swagger UI Instructions:**
You can click the green **"Authorize"** button (top right corner), \\
enter your API Key into the \`reg-api-key\` field, and click Authorize. After that, \\
all test requests on this interface will automatically include the API Key.`,
      },
      servers: spec.servers,
      security: [{ RegistryAPIKey: [] }],
      components: {
        ...filteredExternalComponents,
        securitySchemes: {
          RegistryAPIKey: spec.components.securitySchemes.RegistryAPIKey,
        },
      },
      paths: externalHotelPaths,
    };

    app.use(env.swagger.externalHotelRoute, swaggerUi.serveFiles(externalSpec), swaggerUi.setup());

    app.use(env.swagger.externalHotelApiDocs, (req: any, res: any) => {
      const { host } = req.headers;
      res.status(200).send({ ...externalSpec, host });
    });
  }
};

